n7.scss\\\" as *;\\n@use \\\"builder/section8.scss\\\" as *;\\n@use \\\"builder/section9.scss\\\" as *;\\n@use \\\"builder/section10.scss\\\" as *;\\n@use \\\"builder/section11.scss\\\" as *;\\n@use \\\"builder/section12.scss\\\" as *;\\n@use \\\"burger-menu/burger-menu.scss\\\" as *;\\n\\n@use \\\"base/header.scss\\\" as *;\\n@use \\\"base/footer.scss\\\" as *;\\n@use \\\"base/single-reference.scss\\\" as *;\\n\\n@use \\\"builder/header-service.scss\\\" as *;\\n@use \\\"builder/section-app-glob.scss\\\" as *;\\n@use \\\"builder/section-txt-g-img-d.scss\\\" as *;\\n@use \\\"builder/section-slider-vertical.scss\\\" as *;\\n@use \\\"builder/section-etapes.scss\\\" as *;\\n@use \\\"builder/section-parallax.scss\\\" as *;\\n@use \\\"builder/section-formulaire.scss\\\" as *;\\n\\n@use \\\"builder/header-service.scss\\\" as *;\\n@use \\\"builder/section-app-glob.scss\\\" as *;\\n@use \\\"builder/section-txt-g-img-d.scss\\\" as *;\\n@use \\\"builder/section-slider-vertical.scss\\\" as *;\\n@use \\\"builder/section-etapes.scss\\\" as *;\\n@use \\\"builder/section-parallax.scss\\\" as *;\\n@use \\\"builder/section-formulaire.scss\\\" as *;\\n@use \\\"builder/big_title_about.scss\\\" as *;\\n@use \\\"builder/section_accordeon.scss\\\" as *;\\n@use \\\"builder/text_overlay.scss\\\" as *;\\n\\nbody {\\n  font-family: \\\"Manrope\\\", sans-serif;\\n}\\n\",\"@use \\\"../variables/colors.scss\\\" as *;\\n\\n.container {\\n  width: 80vw;\\n  max-width: 1200px;\\n  margin: auto;\\n\\n  &.flex {\\n    display: flex;\\n\\n    @for $i from 1 through 100 {\\n      .col-#{$i} {\\n        width: $i * 1%;\\n      }\\n    }\\n  }\\n\\n  &.grid {\\n    display: grid;\\n  }\\n}\\n\\n.big_title {\\n  color: $primaryColor;\\n  font-size: 4rem;\\n  line-height: 3.5rem;\\n}\\n\\n.block-img {\\n  img {\\n    width: 100%;\\n    height: 100%;\\n    object-fit: cover;\\n  }\\n}\\n\\n.block-img {\\n  img {\\n    width: 100%;\\n    height: 100%;\\n    object-fit: cover;\\n  }\\n}\\n\\n.block-img {\\n  img {\\n    width: 100%;\\n    height: 100%;\\n    object-fit: cover;\\n  }\\n}\\n\\n.block-img {\\n  img {\\n    width: 100%;\\n    height: 100%;\\n    object-fit: cover;\\n  }\\n}\\n\\n.block-img {\\n  img {\\n    width: 100%;\\n    height: 100%;\\n    object-fit: cover;\\n  }\\n}\\n\\n.block-img {\\n  img {\\n    width: 100%;\\n    height: 100%;\\n    object-fit: cover;\\n  }\\n}\\n\\n.block-img {\\n  img {\\n    width: 100%;\\n    height: 100%;\\n    object-fit: cover;\\n  }\\n}\\n\",\"$primaryColor: #05233c;\\n$secondaryColor: #d3bea1;\\n\\n$txtColor: #222;\\n$lightGray: #e2e2e2;\\n$white: #fff;\\n$black: #000;\\n\\n$whiteTransparent: #ffffff00;\\n\",\"@use \\\"./colors.scss\\\" as *;\\n\\n* {\\n  font-family: \\\"Manrope\\\", sans-serif;\\n}\\n\\nh2 {\\n  font-size: 3.5rem;\\n  line-height: 3.5rem;\\n}\\n\\np {\\n  font-size: 1rem;\\n  line-height: 1.8rem;\\n  font-weight: 100;\\n  font-weight: $txtColor;\\n\\n  & + p {\\n    margin-top: 1rem;\\n  }\\n}\\n\\nstrong {\\n  font-weight: 600;\\n}\\n\\n.section-label,\\n.surtitre {\\n  text-transform: uppercase;\\n  color: $secondaryColor;\\n  letter-spacing: 2px;\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n.btn-cta {\\n  display: flex;\\n  width: fit-content;\\n  align-items: center;\\n  color: $primaryColor;\\n  text-decoration: none;\\n  gap: 120px;\\n  text-decoration: none;\\n  font-size: 0.9rem;\\n  font-weight: 500;\\n  letter-spacing: 3px;\\n  text-transform: uppercase;\\n  padding-bottom: 6px;\\n  border-bottom: 1px solid $primaryColor;\\n  transition:\\n    gap 0.25s ease,\\n    border-color 0.25s ease;\\n\\n  &::after {\\n    content: \\\"↘\\\";\\n    font-size: 0.9rem;\\n    //padding-left: 50px;\\n    color: $secondaryColor;\\n    transform: rotate(0deg);\\n    transition: all ease-in 300ms;\\n  }\\n\\n  &:hover {\\n    border-bottom: 1px solid;\\n    color: $secondaryColor;\\n\\n    &::after {\\n      transform: rotate(-90deg);\\n    }\\n  }\\n\\n  // &::before {\\n  //     content: '';