o-col.scss\\\" as *;\\n@use \\\"builder/section-txt-g-img-d.scss\\\" as *;\\n@use \\\"builder/section-video.scss\\\" as *;\\n@use \\\"builder/section6.scss\\\" as *;\\n@use \\\"builder/section7.scss\\\" as *;\\n@use \\\"builder/swiper.scss\\\" as *;\\n\\n@use \\\"burger-menu/burger-menu.scss\\\" as *;\\n\\nbody {\\n  font-family: \\\"Manrope\\\", sans-serif;\\n}\\n\\n@import \\\"./../../node_modules/hamburgers/_sass/hamburgers/hamburgers.scss\\\";\\n\",\"$primaryColor: #05233c;\\n$secondaryColor: #d3bea1;\\n\\n$darkPrimary: #03111d;\\n\\n$txtColor: #222;\\n$lightGray: #e2e2e2;\\n$white: #fff;\\n$black: #000;\\n\\n/* Transparent */\\n$whiteTransparent: #ffffff00;\\n$lightGrayTransparent: #e2e2e270;\\n\\n/* Dégradés */\\n\\n$blueGradient: linear-gradient($primaryColor 0%, $darkPrimary 100%);\\n\",\"@use \\\"../variables/colors.scss\\\" as *;\\n\\n.container {\\n  width: 80vw;\\n  max-width: 1200px;\\n  margin: auto;\\n\\n  &.flex {\\n    display: flex;\\n\\n    @for $i from 1 through 100 {\\n      .col-#{$i} {\\n        width: $i * 1%;\\n      }\\n    }\\n  }\\n\\n  &.grid {\\n    display: grid;\\n  }\\n\\n  &.-large {\\n    width: 100vw;\\n    max-width: 100vw;\\n  }\\n}\\n\\n.big_title {\\n  color: $primaryColor;\\n  font-size: 4rem;\\n  line-height: 3.5rem;\\n}\\n\\n.block-img {\\n  img {\\n    width: 100%;\\n    height: 100%;\\n    object-fit: cover;\\n  }\\n}\\n\",\"@use \\\"./colors.scss\\\" as *;\\n\\n* {\\n  font-family: \\\"Manrope\\\", sans-serif;\\n}\\n\\nh2 {\\n  font-size: 3.5rem;\\n  line-height: 3.5rem;\\n}\\n\\np {\\n  font-size: 1rem;\\n  line-height: 1.8rem;\\n  font-weight: 100;\\n  font-weight: $txtColor;\\n\\n  & + p {\\n    margin-top: 1rem;\\n  }\\n}\\n\\nstrong {\\n  font-weight: 600;\\n}\\n\\n.section-label,\\n.surtitre {\\n  text-transform: uppercase;\\n  color: $secondaryColor;\\n  letter-spacing: 2px;\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n.btn-cta {\\n  display: flex;\\n  width: fit-content;\\n  align-items: center;\\n  color: $primaryColor;\\n  text-decoration: none;\\n  gap: 120px;\\n  text-decoration: none;\\n  font-size: 0.9rem;\\n  font-weight: 500;\\n  letter-spacing: 3px;\\n  text-transform: uppercase;\\n  padding-bottom: 6px;\\n  border-bottom: 1px solid $primaryColor;\\n  transition:\\n    gap 0.25s ease,\\n    border-color 0.25s ease;\\n\\n  &::after {\\n    content: \\\"\\\";\\n    background: url(\\\"./../../assets/images/arrow-right-gold.svg\\\");\\n    background-size: cover;\\n    font-size: 0.9rem;\\n    color: $secondaryColor;\\n    display: inline-block;\\n    width: 15px;\\n    height: 15px;\\n    margin-bottom: 3px;\\n    transform: rotate(45deg);\\n    transition: all ease-in 300ms;\\n  }\\n\\n  &:hover {\\n    border-bottom: 1px solid;\\n    color: $secondaryColor;\\n\\n    &::after {\\n      transform: rotate(0deg);\\n    }\\n  }\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n\\n.site-header {\\n  width: 100%;\\n  z-index: 100;\\n  padding: 30px 0;\\n  position: relative;\\n\\n  .header-inner {\\n    width: 90vw;\\n    margin: auto;\\n    display: flex;\\n    align-items: center;\\n    justify-content: space-between;\\n    gap: 40px;\\n\\n    .header-logo {\\n      flex-shrink: 0;\\n      width: 250px;\\n      display: block;\\n\\n      img {\\n        width: 100%;\\n        height: auto;\\n        display: block;\\n      }\\n    }\\n\\n    .header-nav {\\n      flex: 1;\\n      display: flex;\\n      justify-content: flex-end;\\n\\n      .navbar {\\n        list-style: none;\\n        display: flex;\\n        align-items: center;\\n        gap: 40px;\\n        margin: 0;\\n        padding: 0;\\n\\n        > li {\\n          position: relative;\\n          color: $white;\\n\\n          &::after {\\n            content: \\\"\\\";\\n            display: block;\\n            width: 0px;\\n            margin-top: 10px;\\n            border-bottom: 2px solid;\\n            transition: all ease-in 300ms;\\n          }\\n\\n          &.current-menu-item {\\n            &::after {\\n              width: 50px;\\n            }\\n          }\\n\\n          > a {\\n            text-decoration: none;\\n            font-size: 0.8rem;\\n            letter-spacing: 1px;\\n            text-transform: uppercase;\\n            white-space: nowrap;\\n            display: flex;\\n            align-items: center;\\n            gap: 6px;\\n            transition: opacity 0.2s ease;\\n\\n            &:hover {\\n              opacity: 0.7;\\n            }\\n          }\\n\\n          &.menu-item-has-children {\\n            > a::after {\\n              content: \\\"\\\";\\n              display: inline-block;\\n              width: 0;\\n              height: 0;\\n              border-left: 4px solid transparent;\\n              border-right: 4px solid transparent;\\n              border-top: 5px solid $white;\\n              margin-top: 2px;\\n              transition: transform 0.2s ease;\\n            }\\n\\n            .sub-menu {\\n              position: absolute;\\n              top: calc(100% + 20px);\\n              left: 0;\\n              background-color: rgba(255, 255, 255, 0.6);\\n              min-width: 220px;\\n              list-style: none;\\n              padding: 0;\\n              margin: 0;\\n              opacity: 0;\\n              visibility: hidden;\\n              transform: translateY(-6px);\\n              transition:\\n                opacity 0.25s ease,\\n                transform 0.25s ease,\\n                visibility 0.25s;\\n\\n              li {\\n                a {\\n                  display: block;\\n                  padding: 12px 20px;\\n                  font-size: 0.75rem;\\n                  letter-spacing: 0.08em;\\n                  color: $primaryColor;\\n                  text-decoration: none;\\n                  border-bottom: 1px solid $lightGray;\\n                  transition: color 0.2s ease;\\n\\n                  &:hover {\\n                    color: $secondaryColor;\\n                  }\\n                }\\n\\n                &:last-child a {\\n                  border-bottom: none;\\n                }\\n              }\\n            }\\n\\n            &:hover {\\n              > a::after {\\n                transform: rotate(180deg);\\n              }\\n\\n              .sub-menu {\\n                opacity: 1;\\n                visibility: visible;\\n                transform: translateY(0);\\n              }\\n            }\\n          }\\n        }\\n      }\\n    }\\n  }\\n\\n  .header-actions {\\n    display: flex;\\n    align-items: center;\\n    gap: 30px;\\n    flex-shrink: 0;\\n\\n    .header-separator {\\n      display: block;\\n      width: 1px;\\n      height: 36px;\\n      background-color: rgba(255, 255, 255, 0.4);\\n    }\\n\\n    .hamburger {\\n      .hamburger-inner,\\n      .hamburger-inner::before,\\n      .hamburger-inner::after {\\n        background-color: $white !important;\\n      }\\n    }\\n  }\\n\\n  &.-frontpage {\\n    position: absolute;\\n    top: 0;\\n    left: 0;\\n  }\\n\\n  &.-negatif-header {\\n    position: relative;\\n\\n    .header-inner {\\n      .header-nav {\\n        .navbar {\\n          > li {\\n            color: $primaryColor;\\n          }\\n        }\\n      }\\n    }\\n\\n    .header-actions {\\n      .header-separator {\\n        background-color: $primaryColor;\\n      }\\n\\n      .hamburger {\\n        .hamburger-box {\\n          .hamburger-inner,\\n          .hamburger-inner::before,\\n          .hamburger-inner::after {\\n            background-color: $primaryColor !important;\\n          }\\n        }\\n      }\\n    }\\n  }\\n\\n  .header-actions {\\n    .hamburger {\\n      &.is-active {\\n        .hamburger-box {\\n          .hamburger-inner::before,\\n          .hamburger-inner::after {\\n            background-color: $white !important;\\n          }\\n\\n          .hamburger-inner {\\n            background-color: transparent !important;\\n          }\\n        }\\n      }\\n    }\\n  }\\n}\\n\\n.mobile-menu {\\n  position: fixed;\\n  inset: 0;\\n  background-color: $primaryColor;\\n  z-index: 99;\\n  display: flex;\\n  align-items: center;\\n  justify-content: center;\\n  opacity: 0;\\n  visibility: hidden;\\n  transform: translateX(100%);\\n  transition:\\n    transform 0.4s ease,\\n    opacity 0.3s ease,\\n    visibility 0.4s;\\n  height: 100vh;\\n\\n  &.is-open {\\n    opacity: 1;\\n    visibility: visible;\\n    transform: translateX(0);\\n  }\\n\\n  .mobile-navbar {\\n    list-style: none;\\n    padding: 0;\\n    margin: 0;\\n    text-align: center;\\n\\n    > li {\\n      padding: 16px 0;\\n\\n      > a {\\n        color: $white;\\n        text-decoration: none;\\n        font-size: 1.4rem;\\n        letter-spacing: 0.12em;\\n        text-transform: uppercase;\\n        transition: color 0.2s ease;\\n\\n        &:hover {\\n          color: $secondaryColor;\\n        }\\n      }\\n\\n      .sub-menu {\\n        list-style: none;\\n        padding: 10px 0 0;\\n        margin: 0;\\n\\n        li {\\n          padding: 6px 0;\\n\\n          a {\\n            font-size: 0.95rem;\\n            color: rgba(255, 255, 255, 0.6);\\n            text-decoration: none;\\n            letter-spacing: 0.06em;\\n            transition: color 0.2s ease;\\n\\n            &:hover {\\n              color: $white;\\n            }\\n          }\\n        }\\n      }\\n    }\\n  }\\n}\\n\\n// Responsive\\n\\n@media (max-width: 768px) {\\n  .site-header {\\n    padding: 20px;\\n  }\\n\\n  .header-nav {\\n    display: none;\\n  }\\n\\n  .header-separator {\\n    display: none;\\n  }\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n\\n.site-footer {\\n    background-color: $primaryColor;\\n    padding: 150px;\\n    position: relative;\\n    margin-top: 100px;\\n\\n    .footer-top {\\n        display: flex;\\n        justify-content: space-between;\\n        align-items: flex-start;\\n        margin-bottom: 60px;\\n\\n        .footer-left {\\n            width: 50%;\\n            display: flex;\\n            flex-direction: column;\\n            gap: 40px;\\n\\n            .footer-titre {\\n                color: $white;\\n                font-size: 4rem;\\n                font-weight: 700;\\n                line-height: 1.1;\\n            }\\n\\n            .footer-arrow {\\n                width: 40px;\\n                height: 40px;\\n                color: $secondaryColor;\\n                stroke: $secondaryColor;\\n                margin-left: 300px;\\n           \\n            }\\n\\n            \\n        }\\n\\n        .footer-right {\\n            width: 40%;\\n            padding-top: 80px;\\n\\n            .footer-texte {\\n                p{\\n                    color: $white;\\n                    font-size: 1rem;\\n                    line-height: 1.7;\\n                }\\n            }\\n        }\\n    }\\n\\n    .footer-lien {\\n        width: fit-content;\\n        display: block;\\n                color: $white;\\n                text-decoration: none;\\n                font-size: 1.5rem;\\n                letter-spacing: 0.05em;\\n                margin: 20px auto;\\n                text-align: center;\\n\\n                &:hover {\\n                    text-decoration: underline;\\n                }\\n            }\\n\\n    .footer-bottom {\\n        display: flex;\\n        justify-content: space-between;\\n        align-items: center;\\n        border-top: 0.5px solid $white;\\n        padding-top: 30px;\\n\\n        .footer-made-by {\\n            p{   \\n                color: $white;\\n            font-size: 0.9rem;\\n        \\n        \\n        }\\n         \\n        }\\n\\n        .footer-nav {\\n            display: flex;\\n            gap: 30px;\\n            list-style: none;\\n            margin: 0;\\n            padding: 0;\\n\\n            li a {\\n               color: $white;\\n                text-decoration: none;\\n                font-size: 0.7rem;\\n                letter-spacing: 0.15em;\\n                text-transform: uppercase;\\n\\n                &:hover {\\n                    color: $secondaryColor;\\n                }\\n            }\\n        }\\n    }\\n}\\n\\n.scroll-top {\\nposition: fixed;\\nbottom: 30px;\\nright: 30px;\\nwidth: 44px;\\nheight: 44px;\\nbackground-color: $secondaryColor;\\ncolor: $white;\\ndisplay: flex;\\nalign-items: center;\\njustify-content: center;\\ntext-decoration: none;\\nfont-size: 2rem;\\nz-index: 100;\\nopacity: 0;\\nvisibility: hidden;\\ntransition: opacity 0.3s;\\n&.visible {\\nopacity: 1;\\nvisibility: visible;\\n    }\\n}\",\".galerie-reference {\\n  .swiper-reference {\\n    height: 90vh;\\n\\n    .swiper-slide {\\n      img {\\n        object-fit: cover;\\n        width: 100%;\\n        height: 100%;\\n      }\\n    }\\n  }\\n}\\n\\n.bloc-reference {\\n  padding-top: 150px;\\n\\n  .container {\\n    gap: 100px;\\n\\n    .col-g {\\n      .block-img {\\n        height: 600px;\\n        max-height: 700px;\\n        width: 100%;\\n      }\\n    }\\n\\n    .col-d {\\n      .section-informations {\\n        padding: 0 100px 100px;\\n        display: flex;\\n        flex-direction: column;\\n        gap: 20px;\\n\\n        p {\\n          font-weight: 200;\\n\\n          strong {\\n            font-weight: 400;\\n          }\\n        }\\n      }\\n\\n      .block-img {\\n        height: 800px;\\n        max-height: 900px;\\n      }\\n    }\\n  }\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n\\n.from-bottom,\\n.from-left,\\n.from-right,\\n.from-top {\\n  opacity: 0;\\n}\\n\\n%anim-fade-base {\\n  animation-duration: 0.8s;\\n  animation-timing-function: cubic-bezier(0.39, 0.575, 0.565, 1);\\n  animation-fill-mode: both;\\n}\\n\\n.-slow {\\n  animation-delay: 0.3s;\\n}\\n\\n.-veryslow {\\n  animation-delay: 0.6s;\\n}\\n\\n.will-animate {\\n  will-change: transform, opacity;\\n}\\n\\n// -------------------------------------\\n// KEYFRAMES - FADE\\n// -------------------------------------\\n\\n@keyframes fade-in-top {\\n  from {\\n    opacity: 0;\\n    transform: translateY(-15%);\\n  }\\n\\n  to {\\n    opacity: 1;\\n    transform: translateY(0);\\n  }\\n}\\n\\n@keyframes fade-in-right {\\n  from {\\n    opacity: 0;\\n    transform: translateX(15%);\\n  }\\n\\n  to {\\n    opacity: 1;\\n    transform: translateX(0);\\n  }\\n}\\n\\n@keyframes fade-in-bottom {\\n  from {\\n    opacity: 0;\\n    transform: translateY(15%);\\n  }\\n\\n  to {\\n    opacity: 1;\\n    transform: translateY(0);\\n  }\\n}\\n\\n@keyframes fade-in-left {\\n  from {\\n    opacity: 0;\\n    transform: translateX(-15%);\\n  }\\n\\n  to {\\n    opacity: 1;\\n    transform: translateX(0);\\n  }\\n}\\n\\n// -------------------------------------\\n// CLASSES - FADE IN\\n// -------------------------------------\\n\\n.fade-in-top {\\n  @extend %anim-fade-base;\\n  animation-name: fade-in-top;\\n\\n  &.-slow {\\n    animation-delay: 0.3s;\\n  }\\n\\n  &.-veryslow {\\n    animation-delay: 0.6s;\\n  }\\n}\\n\\n.fade-in-right {\\n  @extend %anim-fade-base;\\n  animation-name: fade-in-right;\\n\\n  &.-slow {\\n    animation-delay: 0.3s;\\n  }\\n\\n  &.-veryslow {\\n    animation-delay: 0.6s;\\n  }\\n}\\n\\n.fade-in-bottom {\\n  @extend %anim-fade-base;\\n  animation-name: fade-in-bottom;\\n\\n  &.-slow {\\n    animation-delay: 0.3s;\\n  }\\n\\n  &.-veryslow {\\n    animation-delay: 0.6s;\\n  }\\n}\\n\\n.fade-in-left {\\n  @extend %anim-fade-base;\\n  animation-name: fade-in-left;\\n\\n  &.-slow {\\n    animation-delay: 0.3s;\\n  }\\n\\n  &.-veryslow {\\n    animation-delay: 0.6s;\\n  }\\n}\\n\\n// -------------------------------------\\n// CLASSES - FADE OUT\\n// -------------------------------------\\n\\n.fade-out-top {\\n  @extend %anim-fade-base;\\n  animation-name: fade-in-top;\\n  animation-direction: reverse;\\n\\n  &.-slow {\\n    animation-delay: 0.3s;\\n  }\\n\\n  &.-veryslow {\\n    animation-delay: 0.6s;\\n  }\\n}\\n\\n.fade-out-right {\\n  @extend %anim-fade-base;\\n  animation-name: fade-in-right;\\n  animation-direction: reverse;\\n\\n  &.-slow {\\n    animation-delay: 0.3s;\\n  }\\n\\n  &.-veryslow {\\n    animation-delay: 0.6s;\\n  }\\n}\\n\\n.fade-out-bottom {\\n  @extend %anim-fade-base;\\n  animation-name: fade-in-bottom;\\n  animation-direction: reverse;\\n\\n  &.-slow {\\n    animation-delay: 0.3s;\\n  }\\n\\n  &.-veryslow {\\n    animation-delay: 0.6s;\\n  }\\n}\\n\\n.fade-out-left {\\n  @extend %anim-fade-base;\\n  animation-name: fade-in-left;\\n  animation-direction: reverse;\\n\\n  &.-slow {\\n    animation-delay: 0.3s;\\n  }\\n\\n  &.-veryslow {\\n    animation-delay: 0.6s;\\n  }\\n}\\n\\n// -------------------------------------\\n// KEYFRAMES - LOOP\\n// -------------------------------------\\n\\n@keyframes up-and-down {\\n  0% {\\n    top: 1px;\\n  }\\n\\n  50% {\\n    top: -1px;\\n  }\\n\\n  100% {\\n    top: 1px;\\n  }\\n}\\n\\n@keyframes pulse {\\n  0% {\\n    transform: scale(1);\\n  }\\n\\n  50% {\\n    transform: scale(1.05);\\n  }\\n\\n  100% {\\n    transform: scale(1);\\n  }\\n}\\n\\n// -------------------------------------\\n// CLASSES - LOOP\\n// -------------------------------------\\n\\n.anim-up-and-down {\\n  animation: up-and-down 1.5s ease-in-out infinite;\\n}\\n\\n.anim-pulse {\\n  animation: pulse 1.5s ease-in-out infinite;\\n}\\n\\n// -------------------------------------\\n// KEYFRAMES - ROTATION\\n// -------------------------------------\\n\\n@keyframes rotate-180 {\\n  from {\\n    transform: rotate(0deg);\\n  }\\n\\n  to {\\n    transform: rotate(180deg);\\n  }\\n}\\n\\n@mixin rotate-180($duration: 0.4s, $ease: ease) {\\n  animation: rotate-180 $duration $ease forwards;\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n\\n.section-service-header {\\n  margin-top: -220px;\\n  background-color: $primaryColor;\\n  height: 30vh;\\n  width: 100vw;\\n  min-height: 550px;\\n  display: flex;\\n  align-items: flex-end;\\n  justify-content: flex-end;\\n\\n  .container {\\n    m