 width: 100%;\\n        height: 100%;\\n        object-fit: cover;\\n        display: block;\\n        transform: scale(1);\\n        filter: brightness(1);\\n        transition: all ease-in 200ms;\\n      }\\n\\n      .actu-card-plus {\\n        position: absolute;\\n        bottom: 0;\\n        right: 0;\\n        width: 50px;\\n        height: 50px;\\n        background-color: $white;\\n        color: $primaryColor;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        font-size: 1.2rem;\\n        text-decoration: none;\\n      }\\n    }\\n\\n    .actu-card-cat {\\n      display: block;\\n      font-size: 0.65rem;\\n      letter-spacing: 0.15em;\\n      text-transform: uppercase;\\n      color: $secondaryColor;\\n      margin-bottom: 10px;\\n      cursor: pointer;\\n    }\\n\\n    .actu-card-text {\\n      font-size: 0.9rem;\\n      line-height: 1.6;\\n      color: $txtColor;\\n      cursor: pointer;\\n    }\\n\\n    &:first-child {\\n      grid-column: span 2;\\n    }\\n\\n    &:hover {\\n      .actu-card-img {\\n        img {\\n          transform: scale(1.05);\\n          filter: brightness(0.6);\\n        }\\n      }\\n\\n      .actu-card-plus {\\n        background-color: $primaryColor;\\n        color: $white;\\n\\n        .btn-plus-icon {\\n          @include rotate-180;\\n        }\\n      }\\n    }\\n\\n    /*** Animation ***/\\n\\n    &.is-hidden {\\n      transform: scale(0.8);\\n      opacity: 0;\\n      pointer-events: none;\\n    }\\n\\n    &.is-gone {\\n      display: none;\\n    }\\n  }\\n\\n  .actu-btn-wrap {\\n    display: flex;\\n    justify-content: center;\\n\\n    .actu-btn {\\n      display: inline-block;\\n      background-color: $primaryColor;\\n      color: $white;\\n      text-decoration: none;\\n      font-size: 0.7rem;\\n      letter-spacing: 0.2em;\\n      text-transform: uppercase;\\n      padding-top: 16px;\\n      padding-bottom: 16px;\\n      padding-left: 40px;\\n      padding-right: 40px;\\n    }\\n  }\\n}\\n\\n@media (max-width: 1024px) {\\n  .section-actu .actu-grid {\\n    grid-template-columns: repeat(2, 1fr);\\n  }\\n}\\n\\n@media (max-width: 768px) {\\n  .section-actu {\\n    padding-top: 50px;\\n    padding-bottom: 50px;\\n    padding-left: 5%;\\n    padding-right: 5%;\\n\\n    .actu-grid {\\n      grid-template-columns: 1fr;\\n    }\\n  }\\n}\\n\",\"@use \\\"./../variables/base.scss\\\" as *;\\n@use \\\"./../variables/colors.scss\\\" as *;\\n@use \\\"./../variables/fonts.scss\\\" as *;\\n@use \\\"./../variables/cta.scss\\\" as *;\\n\\n.section-approche-globale {\\n  padding: 100px 0;\\n\\n  .container {\\n    h2 {\\n      font-size: 5rem;\\n      line-height: 4.5rem;\\n      margin: 30px 0;\\n      color: $primaryColor;\\n    }\\n\\n    &.grid {\\n      grid-template-columns: repeat(4, 1fr);\\n      gap: 20px;\\n      margin: 50px auto;\\n\\n      .card {\\n        aspect-ratio: 1;\\n        padding: 30px;\\n        border: 1px solid $lightGray;\\n        display: flex;\\n        align-items: flex-end;\\n        justify-content: flex-start;\\n\\n        .content-card {\\n          max-width: 50%;\\n          display: flex;\\n          flex-direction: column;\\n          gap: 20px;\\n\\n          .block-img {\\n            width: 60px;\\n            height: 60px;\\n          }\\n\\n          h3 {\\n            font-weight: 500;\\n            color: $primaryColor;\\n          }\\n\\n          .btn-cta {\\n            text-decoration: none;\\n            border-bottom: none;\\n          }\\n        }\\n      }\\n    }\\n\\n    .btn-cta {\\n      &.section {\\n        background-color: $secondaryColor;\\n        color: $white;\\n        padding: 15px 50px;\\n        border-bottom: none;\\n        margin: auto;\\n        transition: all ease-in 200ms;\\n\\n        &::after {\\n          color: $white;\\n        }\\n\\n        &:hover {\\n          background-color: $primaryColor;\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@use \\\"./..