{\\n    opacity: 1;\\n    transform: translateX(0);\\n  }\\n}\\n\\n// -------------------------------------\\n// CLASSES - FADE IN\\n// -------------------------------------\\n\\n.fade-in-top {\\n  @extend %anim-fade-base;\\n  animation-name: fade-in-top;\\n\\n  &.-slow {\\n    animation-delay: 0.3s;\\n  }\\n\\n  &.-veryslow {\\n    animation-delay: 0.6s;\\n  }\\n}\\n\\n.fade-in-right {\\n  @extend %anim-fade-base;\\n  animation-name: fade-in-right;\\n\\n  &.-slow {\\n    animation-delay: 0.3s;\\n  }\\n\\n  &.-veryslow {\\n    animation-delay: 0.6s;\\n  }\\n}\\n\\n.fade-in-bottom {\\n  @extend %anim-fade-base;\\n  animation-name: fade-in-bottom;\\n\\n  &.-slow {\\n    animation-delay: 0.3s;\\n  }\\n\\n  &.-veryslow {\\n    animation-delay: 0.6s;\\n  }\\n}\\n\\n.fade-in-left {\\n  @extend %anim-fade-base;\\n  animation-name: fade-in-left;\\n\\n  &.-slow {\\n    animation-delay: 0.3s;\\n  }\\n\\n  &.-veryslow {\\n    animation-delay: 0.6s;\\n  }\\n}\\n\\n// -------------------------------------\\n// CLASSES - FADE OUT\\n// -------------------------------------\\n\\n.fade-out-top {\\n  @extend %anim-fade-base;\\n  animation-name: fade-in-top;\\n  animation-direction: reverse;\\n\\n  &.-slow {\\n    animation-delay: 0.3s;\\n  }\\n\\n  &.-veryslow {\\n    animation-delay: 0.6s;\\n  }\\n}\\n\\n.fade-out-right {\\n  @extend %anim-fade-base;\\n  animation-name: fade-in-right;\\n  animation-direction: reverse;\\n\\n  &.-slow {\\n    animation-delay: 0.3s;\\n  }\\n\\n  &.-veryslow {\\n    animation-delay: 0.6s;\\n  }\\n}\\n\\n.fade-out-bottom {\\n  @extend %anim-fade-base;\\n  animation-name: fade-in-bottom;\\n  animation-direction: reverse;\\n\\n  &.-slow {\\n    animation-delay: 0.3s;\\n  }\\n\\n  &.-veryslow {\\n    animation-delay: 0.6s;\\n  }\\n}\\n\\n.fade-out-left {\\n  @extend %anim-fade-base;\\n  animation-name: fade-in-left;\\n  animation-direction: reverse;\\n\\n  &.-slow {\\n    animation-delay: 0.3s;\\n  }\\n\\n  &.-veryslow {\\n    animation-delay: 0.6s;\\n  }\\n}\\n\\n// -------------------------------------\\n// KEYFRAMES - LOOP\\n// -------------------------------------\\n\\n@keyframes up-and-down {\\n  0% {\\n    top: 1px;\\n  }\\n\\n  50% {\\n    top: -1px;\\n  }\\n\\n  100% {\\n    top: 1px;\\n  }\\n}\\n\\n@keyframes pulse {\\n  0% {\\n    transform: scale(1);\\n  }\\n\\n  50% {\\n    transform: scale(1.05);\\n  }\\n\\n  100% {\\n    transform: scale(1);\\n  }\\n}\\n\\n// -------------------------------------\\n// CLASSES - LOOP\\n// -------------------------------------\\n\\n.anim-up-and-down {\\n  animation: up-and-down 1.5s ease-in-out infinite;\\n}\\n\\n.anim-pulse {\\n  animation: pulse 1.5s ease-in-out infinite;\\n}\\n\\n// -------------------------------------\\n// KEYFRAMES - ROTATION\\n// -------------------------------------\\n\\n@keyframes rotate-180 {\\n  from {\\n    transform: rotate(0deg);\\n  }\\n\\n  to {\\n    transform: rotate(180deg);\\n  }\\n}\\n\\n@mixin rotate-180($duration: 0.4s, $ease: ease) {\\n  animation: rotate-180 $duration $ease forwards;\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n\\n.section-service-header {\\n  margin-top: 0px;\\n  background-color: $primaryColor;\\n  height: 30vh;\\n  width: 100vw;\\n  min-height: 550px;\\n  display: flex;\\n  align-items: flex-end;\\n  justify-content: flex-end;\\n\\n  .container {\\n    margin: 0;\\n    align-items: flex-end;\\n    justify-content: space-between;\\n    width: 90vw;\\n    max-width: 1400px;\\n\\n    .colg {\\n      h1 {\\n        color: $white;\\n        font-size: 7rem;\\n        line-height: 5rem;\\n        font-weight: 700;\\n      }\\n    }\\n\\n    .cold {\\n      .block-cta {\\n        background-color: $white;\\n        height: 60px;\\n        width: 400px;\\n        display: flex;\\n        align-items: flex-end;\\n        justify-content: center;\\n      }\\n    }\\n  }\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n@use \\\"./../base/animations.scss\\\" as *;\\n\\n.section-actu {\\n  background-