-bottom: 50px;\\n\\n    strong {\\n      font-weight: 700;\\n    }\\n  }\\n\\n  /* Ajout filtre */\\n\\n  .section-filter {\\n    display: flex;\\n    gap: 10px;\\n\\n    button {\\n      text-transform: uppercase;\\n      color: $lightGray;\\n      transition: all ease-in 300ms;\\n\\n      & + button {\\n        &::before {\\n          content: \\\"-\\\";\\n          margin-right: 10px;\\n        }\\n      }\\n\\n      &.active {\\n        color: $secondaryColor;\\n      }\\n    }\\n  }\\n\\n  /***************/\\n\\n  .actu-grid {\\n    display: grid;\\n    grid-template-columns: repeat(4, 1fr);\\n    gap: 30px;\\n    margin: 100px auto 50px;\\n    align-items: start;\\n  }\\n\\n  .actu-card {\\n    transform: scale(1);\\n    opacity: 1;\\n    transition:\\n      transform 0.3s ease,\\n      opacity 0.3s ease;\\n    transform-origin: center;\\n\\n    .actu-card-img {\\n      position: relative;\\n      background-color: $lightGray;\\n      height: 250px;\\n      overflow: hidden;\\n      margin-bottom: 15px;\\n      cursor: pointer;\\n\\n      img {\\n        width: 100%;\\n        height: 100%;\\n        object-fit: cover;\\n        display: block;\\n        transform: scale(1);\\n        filter: brightness(1);\\n        transition: all ease-in 200ms;\\n      }\\n\\n      .actu-card-plus {\\n        position: absolute;\\n        bottom: 0;\\n        right: 0;\\n        width: 50px;\\n        height: 50px;\\n        background-color: $white;\\n        color: $primaryColor;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        font-size: 1.2rem;\\n        text-decoration: none;\\n      }\\n    }\\n\\n    .actu-card-cat {\\n      display: block;\\n      font-size: 0.65rem;\\n      letter-spacing: 0.15em;\\n      text-transform: uppercase;\\n      color: $secondaryColor;\\n      margin-bottom: 10px;\\n      cursor: pointer;\\n    }\\n\\n    .actu-card-text {\\n      font-size: 0.9rem;\\n      line-height: 1.6;\\n      color: $txtColor;\\n      cursor: pointer;\\n    }\\n\\n    &:first-child {\\n      grid-column: span 2;\\n    }\\n\\n    &:hover {\\n      .actu-card-img {\\n        img {\\n          transform: scale(1.05);\\n          filter: brightness(0.6);\\n        }\\n      }\\n\\n      .actu-card-plus {\\n        background-color: $primaryColor;\\n        color: $white;\\n\\n        .btn-plus-icon {\\n          @include rotate-180;\\n        }\\n      }\\n    }\\n\\n    /*** Animation ***/\\n\\n    &.is-hidden {\\n      transform: scale(0.8);\\n      opacity: 0;\\n      pointer-events: none;\\n    }\\n\\n    &.is-gone {\\n      display: none;\\n    }\\n  }\\n\\n  .actu-btn-wrap {\\n    display: flex;\\n    justify-content: center;\\n\\n    .actu-btn {\\n      display: inline-block;\\n      background-color: $primaryColor;\\n      color: $white;\\n      text-decoration: none;\\n      font-size: 0.7rem;\\n      letter-spacing: 0.2em;\\n      text-transform: uppercase;\\n      padding-top: 16px;\\n      padding-bottom: 16px;\\n      padding-left: 40px;\\n      padding-right: 40px;\\n    }\\n  }\\n}\\n\\n@media (max-width: 1024px) {\\n  .section-actu .actu-grid {\\n    grid-template-columns: repeat(2, 1fr);\\n  }\\n}\\n\\n@media (max-width: 768px) {\\n  .section-actu {\\n    padding-top: 50px;\\n    padding-bottom: 50px;\\n    padding-left: 5%;\\n    padding-right: 5%;\\n\\n    .actu-grid {\\n      grid-template-columns: 1fr;\\n    }\\n  }\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n@use \\\"./../base/animations.scss\\\" as *;\\n\\n.section-references {\\n  background-color: $white;\\n  padding: 100px 0;\\n\\n  .ref-grid {\\n    display: grid;\\n    grid-template-columns: repeat(2, 1fr);\\n    gap: 50px 30px;\\n    align-items: start;\\n  }\\n\\n  .ref-card {\\n    transform: scale(1);\\n    opacity: 1;\\n    transition:\\n      transform 0.3s ease,\\n      opacity 0.3s ease;\\n    transform-origin: center;\\n    padding-bottom: 20px;\\n    border-bottom: 1px solid 