t {\\n      width: 45%;\\n\\n      .video-text {\\n        color: $primaryColor;\\n        font-size: 1.5rem;\\n        font-weight: 300;\\n        line-height: 1.4;\\n        margin-bottom: 30px;\\n      }\\n\\n      .video-line {\\n        border: none;\\n        border-top: 1px solid $lightGray;\\n        margin: 0;\\n      }\\n    }\\n\\n    .video-top-right {\\n      width: 40%;\\n      padding-top: 20px;\\n\\n      .video-paragraph {\\n        color: $txtColor;\\n        font-size: 1rem;\\n        line-height: 1.7;\\n        margin-top: 120px;\\n      }\\n    }\\n  }\\n\\n  .video-wrapper {\\n    background-color: $primaryColor;\\n    width: 100%;\\n    aspect-ratio: 16 / 9;\\n    overflow: hidden;\\n\\n    iframe {\\n      width: 100%;\\n      height: 100%;\\n      display: block;\\n    }\\n  }\\n}\\n\\n@media (max-width: 1024px) {\\n  .section-video {\\n    padding: 60px 0;\\n\\n    .video-top {\\n      .video-top-left {\\n        width: 50%;\\n      }\\n\\n      .video-top-right {\\n        width: 45%;\\n      }\\n    }\\n  }\\n}\\n\\n@media (max-width: 768px) {\\n  .section-video {\\n    padding-top: 50px 5%;\\n\\n    .video-top {\\n      flex-direction: column;\\n      gap: 30px;\\n\\n      .video-top-left {\\n        width: 100%;\\n      }\\n\\n      .video-top-right {\\n        width: 100%;\\n        padding-top: 0;\\n      }\\n    }\\n  }\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n\\n.section-img-text {\\n  background-color: $white;\\n  padding: 90px 0;\\n\\n  .section-img-text-inner {\\n    display: grid;\\n    grid-template-columns: 45% 1fr;\\n    gap: 80px;\\n    align-items: center;\\n  }\\n}\\n\\n.img-col {\\n  padding-bottom: 80px;\\n}\\n\\n.img-wrapper {\\n  position: relative;\\n  padding-bottom: 120px;\\n\\n  .img-large {\\n    display: block;\\n    width: 72%;\\n    aspect-ratio: 3 / 4;\\n    object-fit: cover;\\n    position: relative;\\n    z-index: 1;\\n  }\\n\\n  .img-small {\\n    display: block;\\n    width: 55%;\\n    aspect-ratio: 4 / 3;\\n    object-fit: cover;\\n    position: absolute;\\n    bottom: 0;\\n    right: 0;\\n    z-index: 5;\\n  }\\n}\\n\\n.text-col {\\n  display: flex;\\n  flex-direction: column;\\n  gap: 24px;\\n\\n  .section-label {\\n    display: flex;\\n    align-items: center;\\n    gap: 16px;\\n\\n    span {\\n      font-size: 1rem;\\n      font-weight: 500;\\n      text-transform: uppercase;\\n      color: $primaryColor;\\n    }\\n\\n    &::after {\\n      content: \\\"\\\";\\n      display: block;\\n      height: 1px;\\n      width: 60px;\\n      background-color: $primaryColor;\\n      opacity: 0.4;\\n    }\\n  }\\n\\n  .text-col-paragraph {\\n    font-size: 1rem;\\n    color: $txtColor;\\n    margin-top: 50px;\\n\\n    p {\\n      margin: 0;\\n      color: $secondaryColor;\\n    }\\n  }\\n\\n  .text-col-list {\\n    list-style: none;\\n    padding: 0;\\n    margin: 30px 0;\\n    display: flex;\\n    flex-direction: column;\\n    gap: 10px;\\n\\n    li {\\n      display: flex;\\n      align-items: center;\\n      gap: 14px;\\n      font-size: 1rem;\\n      color: $txtColor;\\n\\n      &::before {\\n        content: \\\"\\\";\\n        display: inline-block;\\n        flex-shrink: 0;\\n        width: 16px;\\n        height: 16px;\\n        background-color: $secondaryColor;\\n        clip-path: polygon(14% 44%, 0 58%, 30% 85%, 100% 14%, 86% 0%, 30% 62%);\\n      }\\n    }\\n  }\\n\\n  .text-col-title {\\n    font-size: 3rem;\\n    line-height: 3rem;\\n  }\\n}\\n\\n@media (max-width: 1024px) {\\n  .section-img-text .section-img-text-inner {\\n    grid-template-columns: 50% 1fr;\\n    gap: 50px;\\n    margin: 0;\\n  }\\n}\\n\\n@media (max-width: 768px) {\\n  .section-img-text {\\n    padding: 60px 0;\\n\\n    .section-img-text-inner {\\n      grid-template-columns: 100%;\\n      gap: 60px;\\n      margin: 0 5%;\\n    }\\n  }\\n\\n  .img-col {\\n    padding-bottom: 60px;\\n  }\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n\\n.section-projects {\\n  background-color: $white;\\n  margin-top: 100px;\\n}\\n\\n.projects-inner {\\n  display: grid;\\n  grid-template-columns: 50% 50%;\\n  min-height: 500px;\\n}\\n\\n.projects-left {\\n  background-color: $primaryColor;\\n  padding: 100px 0 100px 10vw;\\n  display: flex;\\n  flex-direction: column;\\n  justify-content: center;\\n  gap: 150px;\\n\\n  .block-txt {\\n    display: flex;\\n    flex-direction: column;\\n    gap: 20px;\\n\\n    .projects-title {\\n      color: $white;\\n      font-size: 4rem;\\n      line-height: 4rem;\\n    }\\n\\n    .projects-paragraph {\\n      font-size: 1rem;\\n      line-height: 1.5rem;\\n      color: $white;\\n      margin: 0;\\n      width: 500px;\\n    }\\n  }\\n\\n  .btn-cta {\\n    color: $white;\\n    border-bottom: 0.5px solid $white;\\n  }\\n}\\n\\n.projects-right {\\n  position: relative;\\n  overflow: hidden;\\n\\n  .swiper-projects {\\n    width: 100%;\\n    height: 100%;\\n\\n    .swiper-slide {\\n      position: relative;\\n      height: 100%;\\n\\n      img {\\n        width: 100%;\\n        height: 100%;\\n        object-fit: cover;\\n        display: block;\\n      }\\n\\n      .slide-info {\\n        position: absolute;\\n        bottom: 0;\\n        left: 0;\\n        right: 0;\\n        display: flex;\\n        align-items: center;\\n        justify-content: space-between;\\n        padding: 18px 24px;\\n\\n        .slide-location {\\n          font-size: 1.5rem;\\n          color: $white;\\n          font-weight: 400;\\n          text-shadow: 0 0 20px $black;\\n        }\\n\\n        .slide-price {\\n          background-color: $white;\\n          color: $primaryColor;\\n          font-size: 1rem;\\n          font-weight: 500;\\n          padding: 15px 40px;\\n          border-radius: 40px;\\n        }\\n      }\\n    }\\n  }\\n}\\n\\n.projects-controls {\\n  display: flex;\\n  align-items: center;\\n  justify-content: space-between;\\n  margin-top: 30px;\\n  width: 70vw;\\n  max-width: 1000px;\\n\\n  .projects-nav {\\n    display: flex;\\n    gap: 8px;\\n    flex-shrink: 0;\\n\\n    button {\\n      width: 80px;\\n      height: 80px;\\n      border-radius: 50%;\\n      border: 1px solid $lightGray;\\n      background: none;\\n      cursor: pointer;\\n      font-size: 2rem;\\n      color: $primaryColor;\\n      display: flex;\\n      align-items: center;\\n      justify-content: center;\\n      transition:\\n        background-color 0.2s ease,\\n        color 0.2s ease,\\n        border-color 0.2s ease;\\n\\n      &:hover {\\n        background-color: $primaryColor;\\n        color: $white;\\n        border-color: $primaryColor;\\n      }\\n\\n      svg {\\n        fill: $lightGray;\\n        height: 25px;\\n      }\\n\\n      &.projects-next {\\n        svg {\\n          margin-left: 7px;\\n        }\\n      }\\n    }\\n  }\\n\\n  .swiper-scrollbar-projects {\\n    display: flex !important;\\n    align-items: center;\\n    height: 1px;\\n    background-color: $lightGray !important;\\n    width: 60%;\\n    position: relative;\\n\\n    .swiper-scrollbar-drag {\\n      height: 100%;\\n      background-color: $primaryColor;\\n      border-radius: 0;\\n    }\\n  }\\n\\n  .projects-number {\\n    font-size: 5rem;\\n    font-weight: 900;\\n    color: $secondaryColor;\\n    flex-shrink: 0;\\n    min-width: 48px;\\n    text-align: right;\\n  }\\n}\\n\\n// ── Responsive\\n\\n@media (max-width: 768px) {\\n  .projects-inner {\\n    grid-template-columns: 100%;\\n  }\\n\\n  .projects-right {\\n    min-height: 300px;\\n  }\\n\\n  .projects-left {\\n    padding: 50px;\\n  }\\n\\n  .projects-controls {\\n    padding: 20px;\\n  }\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n\\n.slider-fullwidth {\\n  position: relative;\\n  width: 100%;\\n  overflow: hidden;\\n}\\n\\n.swiper-fullwidth {\\n  width: 100%;\\n  height: 100vh;\\n\\n  .swiper-slide {\\n    position: relative;\\n    width: 100%;\\n    height: 100%;\\n    overflow: hidden;\\n    display: flex;\\n    align-items: center;\\n    justify-content: center;\\n\\n    .background {\\n      width: 100%;\\n      height: 100%;\\n      position: absolute;\\n      top: 0;\\n      left: 0;\\n      z-index: -1;\\n\\n      img {\\n        width: 100%;\\n        height: 100%;\\n        object-fit: cover;\\n        display: block;\\n        filter: brightness(0.85);\\n      }\\n    }\\n\\n    .content {\\n      position: relative;\\n      z-index: 1;\\n      width: 70%;\\n      max-width: 1200px;\\n\\n      .content-titre {\\n        color: $white;\\n        font-size: 8rem;\\n        line-height: 6.5rem;\\n        font-weight: 300;\\n        margin-top: 40px;\\n        margin-bottom: 80px;\\n\\n        strong {\\n          font-weight: 800;\\n        }\\n      }\\n\\n      .btn-cta {\\n        color: $white;\\n        border-bottom: 1px solid $lightGray;\\n        position: relative;\\n        text-shadow: 0px 0px 10px rgba(0, 0, 0, 0.8);\\n\\n        &:hover {\\n          border-color: $secondaryColor;\\n          color: $secondaryColor;\\n          font-weight: 600;\\n        }\\n      }\\n    }\\n  }\\n\\n  .block-pagination {\\n    position: absolute;\\n    bottom: 0;\\n    right: 0;\\n    z-index: 2;\\n    background-color: $white;\\n    width: clamp(220px, 30vw, 450px);\\n    height: 100px;\\n    padding: 0 50px;\\n    display: flex;\\n    align-items: center;\\n    justify-content: space-between;\\n    gap: 20px;\\n\\n    .block-scrollbar {\\n      display: flex;\\n      align-items: center;\\n      gap: 10px;\\n      flex: 1;\\n\\n      .number-slide {\\n        font-size: 1rem;\\n        font-weight: 300;\\n        letter-spacing: 0.08em;\\n        color: $primaryColor;\\n        min-width: 18px;\\n      }\\n\\n      .swiper-scrollbar {\\n        flex: 1;\\n        height: 2px;\\n        background-color: $lightGray;\\n        border-radius: 0;\\n        position: relative;\\n        top: 0;\\n        left: auto;\\n\\n        .swiper-scrollbar-drag {\\n          height: 100%;\\n          background-color: $secondaryColor;\\n          border-radius: 0;\\n          cursor: pointer;\\n        }\\n      }\\n    }\\n\\n    .swiper-pagination {\\n      position: relative;\\n      display: flex;\\n      align-items: center;\\n      gap: 10px;\\n      flex-shrink: 0;\\n      width: fit-content;\\n      margin: auto;\\n      top: 0;\\n\\n      .swiper-pagination-bullet {\\n        width: 10px;\\n        height: 10px;\\n        background-color: $lightGray;\\n        border: 1px solid $lightGray;\\n        opacity: 1;\\n        margin: 0;\\n        transition: background-color 0.25s ease;\\n      }\\n\\n      .swiper-pagination-bullet-active {\\n        background-color: $white;\\n        border-color: 1px solid $secondaryColor;\\n      }\\n    }\\n  }\\n}\\n\\n// Responsive\\n\\n@media (max-width: 1024px) {\\n  .swiper-fullwidth {\\n    .swiper-slide .content {\\n      left: 7%;\\n      max-width: 75%;\\n    }\\n  }\\n}\\n\\n@media (max-width: 768px) {\\n  .swiper-fullwidth {\\n    .swiper-slide .content {\\n      left: 5%;\\n      bottom: 90px;\\n      max-width: 90%;\\n    }\\n\\n    .block-pagination {\\n      width: 100%;\\n      height: 72px;\\n      padding: 0 20px;\\n    }\\n  }\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n\\n.menu-burger {\\n  display: flex;\\n  width: 100%;\\n  height: 100vh;\\n  gap: 10px;\\n  align-items: flex-end;\\n  justify-content: space-between;\\n\\n  /* Colonne gauche */\\n\\n  .menu-burger-left {\\n    width: 50%;\\n    position: relative;\\n    display: flex;\\n    align-items: flex-end;\\n    height: 100%;\\n\\n    img {\\n      position: absolute;\\n      object-fit: cover;\\n      z-index: 1;\\n      width: 100%;\\n      height: 100%;\\n      filter: brightness(0.5);\\n    }\\n\\n    .menu-burger-left-bottom {\\n      position: absolute;\\n      z-index: 1;\\n      display: flex;\\n      flex-direction: column;\\n      gap: 20px;\\n      bottom: 80px;\\n      padding-left: 5vw;\\n\\n      .menu-burger-contact {\\n        color: $white;\\n        font-size: 3rem;\\n        font-weight: 300;\\n        display: flex;\\n        flex-direction: column;\\n        gap: 20px;\\n\\n        .menu-burger-contact-name {\\n          text-transform: uppercase;\\n          font-weight: 600;\\n          letter-spacing: 1px;\\n        }\\n\\n        .contact-adresse,\\n        .contact-tel-mail {\\n          p,\\n          p + p {\\n            margin-top: 0;\\n            line-height: 1.5rem;\\n          }\\n        }\\n      }\\n\\n      .menu-burger-socials {\\n        display: flex;\\n        gap: 5px;\\n        align-items: center;\\n        justify-items: center;\\n        margin-top: 50px;\\n\\n        a {\\n          width: 20px;\\n          height: 20px;\\n          display: block;\\n\\n          img {\\n            width: 100%;\\n            height: 100%;\\n            object-fit: contain;\\n            position: relative;\\n            filter: none;\\n          }\\n        }\\n      }\\n    }\\n  }\\n\\n  /* Colonne droite */\\n\\n  .menu-burger-right {\\n    width: 50%;\\n    background-color: $primaryColor;\\n    display: flex;\\n    flex-direction: column;\\n    justify-content: center;\\n    align-items: flex-end;\\n    padding-bottom: 80px;\\n    padding-right: 50px;\\n    gap: 150px;\\n    height: fit-content;\\n\\n    .burger-nav {\\n      width: 100%;\\n\\n      .burger-menu_list {\\n        display: flex;\\n        flex-direction: column;\\n        gap: 10px;\\n\\n        li {\\n          color: $white;\\n          text-transform: uppercase;\\n          letter-spacing: 2px;\\n          display: block;\\n          text-decoration: none;\\n          width: 100%;\\n          text-align: right;\\n\\n          a {\\n            display: flex;\\n            gap: 20px;\\n            justify-content: flex-end;\\n            align-items: flex-end;\\n          }\\n\\n          &.big-menu {\\n            font-size: 2.5rem;\\n            font-weight: 600;\\n            line-height: 3rem;\\n\\n            a {\\n              line-height: 2.5rem;\\n            }\\n          }\\n\\n          &.bg-menu-small {\\n            font-size: 2rem;\\n            font-weight: 300;\\n            line-height: 2.5rem;\\n\\n            a {\\n              line-height: 2rem;\\n            }\\n          }\\n\\n          &.bg-menu-gold {\\n            color: $secondaryColor;\\n            font-size: 1.5rem;\\n\\n            a {\\n              line-height: 1.5rem;\\n            }\\n          }\\n        }\\n      }\\n\\n      li.big-menu + li.bg-menu-small,\\n      li.bg-menu-small + li.bg-menu-gold {\\n        margin-top: 30px;\\n      }\\n\\n      li.bg-menu-gold + li.bg-menu-gold {\\n        margin-top: 0;\\n      }\\n\\n      li.has-arrow a::before {\\n        content: \\\"\\\";\\n        background: url(\\\"./../../assets/images/arrow-right-gold.svg\\\");\\n        background-size: cover;\\n        color: $secondaryColor;\\n        display: inline-block;\\n        width: 15px;\\n        height: 15px;\\n        margin-bottom: 3px;\\n        transform: rotate(45deg);\\n      }\\n    }\\n\\n    .menu-bottom {\\n      width: 100%;\\n\\n      .burger-bottom {\\n        width: fit-content;\\n        text-align: right;\\n        display: flex;\\n        flex-direction: column;\\n        margin-right: 0;\\n        padding-left: 100px;\\n        margin-left: auto;\\n        align-items: flex-end;\\n        border-top: 1px solid $lightGrayTransparent;\\n\\n        .burger-legal-footer {\\n          padding: 0;\\n          margin-top: 40px;\\n          display: flex;\\n          flex-direction: row;\\n          justify-content: flex-end;\\n          gap: 10px;\\n\\n          li {\\n            a {\\n              color: $lightGray;\\n              font-size: 0.8rem;\\n              text-transform: uppercase;\\n              text-decoration: none;\\n            }\\n\\n            & + li {\\n              &::before {\\n                content: \\\"•\\\";\\n                margin-right: 10px;\\n                color: $lightGray;\\n              }\\n            }\\n          }\\n        }\\n\\n        .burger-legal-copy {\\n          display: flex;\\n          justify-content: flex-end;\\n          gap: 10px;\\n          align-items: center;\\n\\n          .burger-legal-links,\\n          .burger-legal-copyright {\\n            color: $lightGray;\\n            font-size: 0.8rem;\\n            letter-spacing: 1px;\\n            text-transform: uppercase;\\n            margin: 0;\\n          }\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@charset \\\"UTF-8\\\";\\n/*!\\n * Hamburgers\\n * @description Tasty CSS-animated hamburgers\\n * @author Jonathan Suh @jonsuh\\n * @site https://jonsuh.com/hamburgers\\n * @link https://github.com/jonsuh/hamburgers\\n */\\n\\n// Settings\\n// ==================================================\\n$hamburger-padding-x           : 15px !default;\\n$hamburger-padding-y           : 15px !default;\\n$hamburger-layer-width         : 40px !default;\\n$hamburger-layer-height        : 4px !default;\\n$hamburger-layer-spacing       : 6px !default;\\n$hamburger-layer-color         : #000 !default;\\n$hamburger-layer-border-radius : 4px !default;\\n$hamburger-hover-opacity       : 0.7 !default;\\n$hamburger-active-layer-color  : $hamburger-layer-color !default;\\n$hamburger-active-hover-opacity: $hamburger-hover-opacity !default;\\n\\n// To use CSS filters as the hover effect instead of opacity,\\n// set $hamburger-hover-use-filter as true and\\n// change the value of $hamburger-hover-filter accordingly.\\n$hamburger-hover-use-filter   : false !default;\\n$hamburger-hover-filter       : opacity(50%) !default;\\n$hamburger-active-hover-filter: $hamburger-hover-filter !default;\\n\\n// Types (Remove or comment out what you don’t need)\\n// ==================================================\\n$hamburger-types: (\\n  3dx,\\n  3dx-r,\\n  3dy,\\n  3dy-r,\\n  3dxy,\\n  3dxy-r,\\n  arrow,\\n  arrow-r,\\n  arrowalt,\\n  arrowalt-r,\\n  arrowturn,\\n  arrowturn-r,\\n  boring,\\n  collapse,\\n  collapse-r,\\n  elastic,\\n  elastic-r,\\n  emphatic,\\n  emphatic-r,\\n  minus,\\n  slider,\\n  slider-r,\\n  spin,\\n  spin-r,\\n  spring,\\n  spring-r,\\n  stand,\\n  stand-r,\\n  squeeze,\\n  vortex,\\n  vortex-r\\n) !default;\\n\\n// Base Hamburger (We need this)\\n// ==================================================\\n@import \\\"base\\\";\\n\\n// Hamburger types\\n// ==================================================\\n@import \\\"types/3dx\\\";\\n@import \\\"types/3dx-r\\\";\\n@import \\\"types/3dy\\\";\\n@import \\\"types/3dy-r\\\";\\n@import \\\"types/3dxy\\\";\\n@import \\\"types/3dxy-r\\\";\\n@import \\\"types/arrow\\\";\\n@import \\\"types/arrow-r\\\";\\n@import \\\"types/arrowalt\\\";\\n@import \\\"types/arrowalt-r\\\";\\n@import \\\"types/arrowturn\\\";\\n@import \\\"types/arrowturn-r\\\";\\n@import \\\"types/boring\\\";\\n@import \\\"types/collapse\\\";\\n@import \\\"types/collapse-r\\\";\\n@import \\\"types/elastic\\\";\\n@import \\\"types/elastic-r\\\";\\n@import \\\"types/emphatic\\\";\\n@import \\\"types/emphatic-r\\\";\\n@import \\\"types/minus\\\";\\n@import \\\"types/slider\\\";\\n@import \\\"types/slider-r\\\";\\n@import \\\"types/spin\\\";\\n@import \\\"types/spin-r\\\";\\n@import \\\"types/spring\\\";\\n@import \\\"types/spring-r\\\";\\n@import \\\"types/stand\\\";\\n@import \\\"types/stand-r\\\";\\n@import \\\"types/squeeze\\\";\\n@import \\\"types/vortex\\\";\\n@import \\\"types/vortex-r\\\";\\n\\n// ==================================================\\n// Cooking up additional types:\\n//\\n// The Sass for each hamburger type should be nested\\n// inside an @if directive to check whether or not\\n// it exists in $hamburger-types so only the CSS for\\n// included types are generated.\\n//\\n// e.g. hamburgers/types/_new-type.scss\\n//\\n// @if index($hamburger-types, new-type) {\\n//   .hamburger--new-type {\\n//     ...\\n//   }\\n// }\\n\",\"@use \\\"sass:math\\\";\\n\\n// Hamburger\\n// ==================================================\\n.hamburger {\\n  padding: $hamburger-padding-y $hamburger-padding-x;\\n  display: inline-block;\\n  cursor: pointer;\\n\\n  transition-property: opacity, filter;\\n  transition-duration: 0.15s;\\n  transition-timing-function: linear;\\n\\n  // Normalize (<button>)\\n  font: inherit;\\n  color: inherit;\\n  text-transform: none;\\n  background-color: transparent;\\n  border: 0;\\n  margin: 0;\\n  overflow: visible;\\n\\n  &:hover {\\n    @if $hamburger-hover-use-filter == true {\\n      filter: $hamburger-hover-filter;\\n    }\\n    @else {\\n      opacity: $hamburger-hover-opacity;\\n    }\\n  }\\n\\n  &.is-active {\\n    &:hover {\\n      @if $hamburger-hover-use-filter == true {\\n        filter: $hamburger-active-hover-filter;\\n      }\\n      @else {\\n        opacity: $hamburger-active-hover-opacity;\\n      }\\n    }\\n\\n    .hamburger-inner,\\n    .hamburger-inner::before,\\n    .hamburger-inner::after {\\n      background-color: $hamburger-active-layer-color;\\n    }\\n  }\\n}\\n\\n.hamburger-box {\\n  width: $hamburger-layer-width;\\n  height: $hamburger-layer-height * 3 + $hamburger-layer-spacing * 2;\\n  display: inline-block;\\n  position: relative;\\n}\\n\\n.hamburger-inner {\\n  display: block;\\n  top: 50%;\\n  margin-top: math.div($hamburger-layer-height, -2);\\n\\n  &,\\n  &::before,\\n  &::after {\\n    width: $hamburger-layer-width;\\n    height: $hamburger-layer-height;\\n    background-color: $hamburger-layer-color;\\n    border-radius: $hamburger-layer-border-radius;\\n    position: absolute;\\n    transition-property: transform;\\n    transition-duration: 0.15s;\\n    transition-timing-function: ease;\\n  }\\n\\n  &::before,\\n  &::after {\\n    content: \\\"\\\";\\n    display: block;\\n  }\\n\\n  &::before {\\n    top: ($hamburger-layer-spacing + $hamburger-layer-height) * -1;\\n  }\\n\\n  &::after {\\n    bottom: ($hamburger-layer-spacing + $hamburger-layer-height) * -1;\\n  }\\n}\\n\",\"@if index($hamburger-types, 3dx) {\\n  /*\\n   * 3DX\\n   */\\n  .hamburger--3dx {\\n    .hamburger-box {\\n      perspective: $hamburger-layer-width * 2;\\n    }\\n\\n    .hamburger-inner {\\n      transition: transform 0.15s cubic-bezier(0.645, 0.045, 0.355, 1),\\n                  background-color 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n\\n      &::before,\\n      &::after {\\n        transition: transform 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        background-color: transparent !important;\\n        transform: rotateY(180deg);\\n\\n        &::before {\\n          transform: translate3d(0, $hamburger-layer-height + $hamburger-layer-spacing, 0) rotate(45deg);\\n        }\\n\\n        &::after {\\n          transform: translate3d(0, ($hamburger-layer-height + $hamburger-layer-spacing) * -1, 0) rotate(-45deg);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, 3dx-r) {\\n  /*\\n   * 3DX Reverse\\n   */\\n  .hamburger--3dx-r {\\n    .hamburger-box {\\n      perspective: $hamburger-layer-width * 2;\\n    }\\n\\n    .hamburger-inner {\\n      transition: transform 0.15s cubic-bezier(0.645, 0.045, 0.355, 1),\\n                  background-color 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n\\n      &::before,\\n      &::after {\\n        transition: transform 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        background-color: transparent !important;\\n        transform: rotateY(-180deg);\\n\\n        &::before {\\n          transform: translate3d(0, $hamburger-layer-height + $hamburger-layer-spacing, 0) rotate(45deg);\\n        }\\n\\n        &::after {\\n          transform: translate3d(0, ($hamburger-layer-height + $hamburger-layer-spacing) * -1, 0) rotate(-45deg);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, 3dy) {\\n  /*\\n   * 3DY\\n   */\\n  .hamburger--3dy {\\n    .hamburger-box {\\n      perspective: $hamburger-layer-width * 2;\\n    }\\n\\n    .hamburger-inner {\\n      transition: transform 0.15s cubic-bezier(0.645, 0.045, 0.355, 1),\\n                  background-color 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n\\n      &::before,\\n      &::after {\\n        transition: transform 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        background-color: transparent !important;\\n        transform: rotateX(-180deg);\\n\\n        &::before {\\n          transform: translate3d(0, $hamburger-layer-height + $hamburger-layer-spacing, 0) rotate(45deg);\\n        }\\n\\n        &::after {\\n          transform: translate3d(0, ($hamburger-layer-height + $hamburger-layer-spacing) * -1, 0) rotate(-45deg);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, 3dy-r) {\\n  /*\\n   * 3DY Reverse\\n   */\\n  .hamburger--3dy-r {\\n    .hamburger-box {\\n      perspective: $hamburger-layer-width * 2;\\n    }\\n\\n    .hamburger-inner {\\n      transition: transform 0.15s cubic-bezier(0.645, 0.045, 0.355, 1),\\n                  background-color 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n\\n      &::before,\\n      &::after {\\n        transition: transform 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        background-color: transparent !important;\\n        transform: rotateX(180deg);\\n\\n        &::before {\\n          transform: translate3d(0, $hamburger-layer-height + $hamburger-layer-spacing, 0) rotate(45deg);\\n        }\\n\\n        &::after {\\n          transform: translate3d(0, ($hamburger-layer-height + $hamburger-layer-spacing) * -1, 0) rotate(-45deg);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, 3dxy) {\\n  /*\\n   * 3DXY\\n   */\\n  .hamburger--3dxy {\\n    .hamburger-box {\\n      perspective: $hamburger-layer-width * 2;\\n    }\\n\\n    .hamburger-inner {\\n      transition: transform 0.15s cubic-bezier(0.645, 0.045, 0.355, 1),\\n                  background-color 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n\\n      &::before,\\n      &::after {\\n        transition: transform 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        background-color: transparent !important;\\n        transform: rotateX(180deg) rotateY(180deg);\\n\\n        &::before {\\n          transform: translate3d(0, $hamburger-layer-height + $hamburger-layer-spacing, 0) rotate(45deg);\\n        }\\n\\n        &::after {\\n          transform: translate3d(0, ($hamburger-layer-height + $hamburger-layer-spacing) * -1, 0) rotate(-45deg);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, 3dxy-r) {\\n  /*\\n   * 3DXY Reverse\\n   */\\n  .hamburger--3dxy-r {\\n    .hamburger-box {\\n      perspective: $hamburger-layer-width * 2;\\n    }\\n\\n    .hamburger-inner {\\n      transition: transform 0.15s cubic-bezier(0.645, 0.045, 0.355, 1),\\n                  background-color 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n\\n      &::before,\\n      &::after {\\n        transition: transform 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        background-color: transparent !important;\\n        transform: rotateX(180deg) rotateY(180deg) rotateZ(-180deg);\\n\\n        &::before {\\n          transform: translate3d(0, $hamburger-layer-height + $hamburger-layer-spacing, 0) rotate(45deg);\\n        }\\n\\n        &::after {\\n          transform: translate3d(0, ($hamburger-layer-height + $hamburger-layer-spacing) * -1, 0) rotate(-45deg);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, arrow) {\\n  /*\\n   * Arrow\\n   */\\n  .hamburger--arrow.is-active {\\n    .hamburger-inner {\\n      &::before {\\n        transform: translate3d($hamburger-layer-width * -0.2, 0, 0) rotate(-45deg) scale(0.7, 1);\\n      }\\n\\n      &::after {\\n        transform: translate3d($hamburger-layer-width * -0.2, 0, 0) rotate(45deg) scale(0.7, 1);\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, arrow-r) {\\n  /*\\n   * Arrow Right\\n   */\\n  .hamburger--arrow-r.is-active {\\n    .hamburger-inner {\\n      &::before {\\n        transform: translate3d($hamburger-layer-width * 0.2, 0, 0) rotate(45deg) scale(0.7, 1);\\n      }\\n\\n      &::after {\\n        transform: translate3d($hamburger-layer-width * 0.2, 0, 0) rotate(-45deg) scale(0.7, 1);\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, arrowalt) {\\n  /*\\n   * Arrow Alt\\n   */\\n  .hamburger--arrowalt {\\n    .hamburger-inner {\\n      &::before {\\n        transition: top 0.1s 0.1s ease,\\n                    transform 0.1s cubic-bezier(0.165, 0.84, 0.44, 1);\\n      }\\n\\n      &::after {\\n        transition: bottom 0.1s 0.1s ease,\\n                    transform 0.1s cubic-bezier(0.165, 0.84, 0.44, 1);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        &::before {\\n          top: 0;\\n          transform: translate3d($hamburger-layer-width * -0.2, $hamburger-layer-width * -0.25, 0) rotate(-45deg) scale(0.7, 1);\\n          transition: top 0.1s ease,\\n                      transform 0.1s 0.1s cubic-bezier(0.895, 0.03, 0.685, 0.22);\\n        }\\n\\n        &::after {\\n          bottom: 0;\\n          transform: translate3d($hamburger-layer-width * -0.2, $hamburger-layer-width * 0.25, 0) rotate(45deg) scale(0.7, 1);\\n          transition: bottom 0.1s ease,\\n                      transform 0.1s 0.1s cubic-bezier(0.895, 0.03, 0.685, 0.22);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, arrowalt-r) {\\n  /*\\n   * Arrow Alt Right\\n   */\\n  .hamburger--arrowalt-r {\\n    .hamburger-inner {\\n      &::before {\\n        transition: top 0.1s 0.1s ease,\\n                    transform 0.1s cubic-bezier(0.165, 0.84, 0.44, 1);\\n      }\\n\\n      &::after {\\n        transition: bottom 0.1s 0.1s ease,\\n                    transform 0.1s cubic-bezier(0.165, 0.84, 0.44, 1);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        &::before {\\n          top: 0;\\n          transform: translate3d($hamburger-layer-width * 0.2, $hamburger-layer-width * -0.25, 0) rotate(45deg) scale(0.7, 1);\\n          transition: top 0.1s ease,\\n                      transform 0.1s 0.1s cubic-bezier(0.895, 0.03, 0.685, 0.22);\\n        }\\n\\n        &::after {\\n          bottom: 0;\\n          transform: translate3d($hamburger-layer-width * 0.2, $hamburger-layer-width * 0.25, 0) rotate(-45deg) scale(0.7, 1);\\n          transition: bottom 0.1s ease,\\n                      transform 0.1s 0.1s cubic-bezier(0.895, 0.03, 0.685, 0.22);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, arrowturn) {\\n  /*\\n   * Arrow Turn\\n   */\\n  .hamburger--arrowturn.is-active {\\n    .hamburger-inner {\\n      transform: rotate(-180deg);\\n\\n      &::before {\\n        transform: translate3d(8px, 0, 0) rotate(45deg) scale(0.7, 1);\\n      }\\n\\n      &::after {\\n        transform: translate3d(8px, 0, 0) rotate(-45deg) scale(0.7, 1);\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, arrowturn-r) {\\n  /*\\n   * Arrow Turn Right\\n   */\\n  .hamburger--arrowturn-r.is-active {\\n    .hamburger-inner {\\n      transform: rotate(-180deg);\\n\\n      &::before {\\n        transform: translate3d(-8px, 0, 0) rotate(-45deg) scale(0.7, 1);\\n      }\\n\\n      &::after {\\n        transform: translate3d(-8px, 0, 0) rotate(45deg) scale(0.7, 1);\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, boring) {\\n  /*\\n   * Boring\\n   */\\n  .hamburger--boring {\\n    .hamburger-inner {\\n      &,\\n      &::before,\\n      &::after {\\n        transition-property: none;\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        transform: rotate(45deg);\\n\\n        &::before {\\n          top: 0;\\n          opacity: 0;\\n        }\\n\\n        &::after {\\n          bottom: 0;\\n          transform: rotate(-90deg);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, collapse) {\\n  /*\\n   * Collapse\\n   */\\n  .hamburger--collapse {\\n    .hamburger-inner {\\n      top: auto;\\n      bottom: 0;\\n      transition-duration: 0.13s;\\n      transition-delay: 0.13s;\\n      transition-timing-function: cubic-bezier(0.55, 0.055, 0.675, 0.19);\\n\\n      &::after {\\n        top: ($hamburger-layer-spacing * 2 + $hamburger-layer-height * 2) * -1;\\n        transition: top 0.2s 0.2s cubic-bezier(0.33333, 0.66667, 0.66667, 1),\\n                    opacity 0.1s linear;\\n      }\\n\\n      &::before {\\n        transition: top 0.12s 0.2s cubic-bezier(0.33333, 0.66667, 0.66667, 1),\\n                    transform 0.13s cubic-bezier(0.55, 0.055, 0.675, 0.19);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        transform: translate3d(0, ($hamburger-layer-spacing + $hamburger-layer-height) * -1, 0) rotate(-45deg);\\n        transition-delay: 0.22s;\\n        transition-timing-function: cubic-bezier(0.215, 0.61, 0.355, 1);\\n\\n        &::after {\\n          top: 0;\\n          opacity: 0;\\n          transition: top 0.2s cubic-bezier(0.33333, 0, 0.66667, 0.33333),\\n                      opacity 0.1s 0.22s linear;\\n        }\\n\\n        &::before {\\n          top: 0;\\n          transform: rotate(-90deg);\\n          transition: top 0.1s 0.16s cubic-bezier(0.33333, 0, 0.66667, 0.33333),\\n                      transform 0.13s 0.25s cubic-bezier(0.215, 0.61, 0.355, 1);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, collapse-r) {\\n  /*\\n   * Collapse Reverse\\n   */\\n  .hamburger--collapse-r {\\n    .hamburger-inner {\\n      top: auto;\\n      bottom: 0;\\n      transition-duration: 0.13s;\\n      transition-delay: 0.13s;\\n      transition-timing-function: cubic-bezier(0.55, 0.055, 0.675, 0.19);\\n\\n      &::after {\\n        top: ($hamburger-layer-spacing * 2 + $hamburger-layer-height * 2) * -1;\\n        transition: top 0.2s 0.2s cubic-bezier(0.33333, 0.66667, 0.66667, 1),\\n                    opacity 0.1s linear;\\n      }\\n\\n      &::before {\\n        transition: top 0.12s 0.2s cubic-bezier(0.33333, 0.66667, 0.66667, 1),\\n                    transform 0.13s cubic-bezier(0.55, 0.055, 0.675, 0.19);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        transform: translate3d(0, ($hamburger-layer-spacing + $hamburger-layer-height) * -1, 0) rotate(45deg);\\n        transition-delay: 0.22s;\\n        transition-timing-function: cubic-bezier(0.215, 0.61, 0.355, 1);\\n\\n        &::after {\\n          top: 0;\\n          opacity: 0;\\n          transition: top 0.2s cubic-bezier(0.33333, 0, 0.66667, 0.33333),\\n                      opacity 0.1s 0.22s linear;\\n        }\\n\\n        &::before {\\n          top: 0;\\n          transform: rotate(90deg);\\n          transition: top 0.1s 0.16s cubic-bezier(0.33333, 0, 0.66667, 0.33333),\\n                      transform 0.13s 0.25s cubic-bezier(0.215, 0.61, 0.355, 1);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@use \\\"sass:math\\\";\\n\\n@if index($hamburger-types, elastic) {\\n  /*\\n   * Elastic\\n   */\\n  .hamburger--elastic {\\n    .hamburger-inner {\\n      top: math.div($hamburger-layer-height, 2);\\n      transition-duration: 0.275s;\\n      transition-timing-function: cubic-bezier(0.68, -0.55, 0.265, 1.55);\\n\\n      &::before {\\n        top: $hamburger-layer-height + $hamburger-layer-spacing;\\n        transition: opacity 0.125s 0.275s ease;\\n      }\\n\\n      &::after {\\n        top: ($hamburger-layer-height * 2) + ($hamburger-layer-spacing * 2);\\n        transition: transform 0.275s cubic-bezier(0.6